import {
  sendAuthenticatedBackendRequest,
  setRefreshToken,
} from '../utils';

let USER = null;
let SET_TIME_MILLISECONDS = null;
let USER_REQUEST_IS_ACTIVE_AT = null;
let USER_RESPONSES = [];
let TIME_DELTA = 10 * 60 * 1000;

function cacheUserEquality(oldUser, newUser) {
  if (oldUser === null) {
    return false;
  }
  if (oldUser.is_anonymous !== newUser.is_anonymous) {
    return false;
  }
  if (oldUser.email_confirmed !== newUser.email_confirmed) {
    return false;
  }
  if (oldUser.subscription.tier !== newUser.subscription.tier) {
    return false;
  }
  return true;
}

function setUserInCache(user) {
  const currentDate = new Date();
  SET_TIME_MILLISECONDS = currentDate.getTime();
  if (user) {
    const cacheEquality = cacheUserEquality(USER, user);
    USER = user;
    if (!cacheEquality) {
      // alert all tabs that the user has changed so they can update content-script cache
      chrome.tabs.query({}, (tabs) => {
        for (let i = 0; i < tabs.length; i++) {
          chrome.tabs.sendMessage(
            tabs[i].id,
            { action: 'event/NEW_USER' },
          ).catch(e => void e);
        }
      });
    }
  }
}

export function getUserAndCache(sendResponse) {
  USER_RESPONSES.push(sendResponse);
  const currentDate = new Date();
  const currentTime = currentDate.getTime();
  if (!USER_REQUEST_IS_ACTIVE_AT || currentTime - USER_REQUEST_IS_ACTIVE_AT > TIME_DELTA) {
    USER_REQUEST_IS_ACTIVE_AT = currentTime;
    sendAuthenticatedBackendRequest('/users/me', 'get', {}, (user) => {
      // If an access token and refresh token are returned, override local cache
      // This helps prevent cases where a user is logged into on the website but
      // not a browser extension
      if (user.access_token && user.refresh_token) {
        const authTokens = {
          refreshToken: user.refresh_token,
          accessToken: user.access_token,
        };
        setRefreshToken(authTokens);
        delete user.access_token;
        delete user.refresh_token;
      }

      USER_REQUEST_IS_ACTIVE_AT = null;
      setUserInCache(user);
      for (let idx = 0; idx < USER_RESPONSES.length; idx += 1) {
        const response = USER_RESPONSES[idx];
        response({ data: user, status: true, success: true });
      }
      USER_RESPONSES = [];
    }, () => {
      USER_REQUEST_IS_ACTIVE_AT = null;
      for (let idx = 0; idx < USER_RESPONSES.length; idx += 1) {
        const response = USER_RESPONSES[idx];
        response({ status: true, success: false });
      }
      USER_RESPONSES = [];
    });
  }
}

export function clearUserCache() {
  USER = null;
  SET_TIME_MILLISECONDS = null;
  USER_REQUEST_IS_ACTIVE_AT = null;
  for (let idx = 0; idx < USER_RESPONSES.length; idx += 1) {
    const response = USER_RESPONSES[idx];
    response({ status: true, success: false });
  }
  USER_RESPONSES = [];
}

export function getUserFromCache() {
  const currentDate = new Date();
  const currentTime = currentDate.getTime();
  if (!USER) {
    return null;
  }
  if (SET_TIME_MILLISECONDS && currentTime - SET_TIME_MILLISECONDS > TIME_DELTA) {
    // refresh user in background if stale
    setTimeout(() => {
      getUserAndCache(() => {});
    }, 0);
  }
  return USER;
}
