export default function saplingExecCommandOverride() {
  const saplingBoundExec = document.execCommand.bind(document);
  document.execCommand = (...args) => {
    if (document.body.dataset.saplingSnippetInsert) {
      Promise.resolve().then((() => {
        saplingBoundExec(...args);
      })).catch(e => void e);
      return true;
    }
    return saplingBoundExec(...args);
  };
}
