export function pluginAvailable(url) {
  if (!url) {
    return false;
  } else if (url.includes('chat.cloudhumans.com')) {
    return true;
  } else if (url.includes('zendesk.com')) {
    return true;
  } else if (url.includes('ujet.co')) {
    return true;
  } else if (url.includes('force.com')) {
    return true;
  } else if (url.includes('connect.aws') || url.includes('awsapps') || url.includes('amazonaws.com')) {
    return true;
  } else if (url.includes('salesiq.zoho.com')) {
    return true;
  } else if (url.includes('intercom.com')) {
    return true;
  } else if (url.includes('agent.')) {
    return true;
  } else if (url.includes('sapling.ai')) {
    return true;
  } else if (url.includes('kustomer')) {
    return true;
  } else if (url.includes('gorgias')) {
    return true;
  } else if (url.includes('bliss.')) {
    return true;
  }
  return false;
}
