import { sendAuthenticatedBackendRequest } from '../utils';
import { SAPLING_ENV } from '../../globals';
import { pluginAvailable } from '../../../src/utils/suggest';

let SUGGEST_PLUGIN = {};
let SUGGEST_HELPERS = {};
let PLUGIN_SET_TIME_MILLISECONDS = {};
let HELPERS_SET_TIME_MILLISECONDS = 0;
let TIME_DELTA = 10 * 60 * 1000; // 10min

export function syncSuggestPluginSettings(tabId, frame) {
  injectRemotePlugins(tabId, frame);
  syncSuggestHelpers(tabId, frame);
}

export function getSuggestHelpers(hostname) {
  let helpersToReturn = {
    greeting: [],
    hold: [],
    connected: [],
    closing: [],
    confirmation: [],
    empathy: [],
  };
  for (const type in SUGGEST_HELPERS) {
    let helpersByType = SUGGEST_HELPERS[type];
    for (const helper of helpersByType) {
      if (helper.hostname && !hostname.includes(helper.hostname)) {
        continue;
      }
      helpersToReturn[type].push(helper);
    }
  }
  return helpersToReturn;
}

function saveSuggestHelpers(helpers) {
  const currentDate = new Date();
  HELPERS_SET_TIME_MILLISECONDS = currentDate.getTime();
  let helpersByType = {
    greeting: [],
    hold: [],
    connected: [],
    closing: [],
    confirmation: [],
    empathy: [],
  };
  for (let idx in helpers) {
    let helper = helpers[idx];
    if (helper.helper_type in helpersByType) {
      helpersByType[helper.helper_type].push(helper);
    }
  }
  SUGGEST_HELPERS = helpersByType;
}

function syncSuggestHelpers(tabId, frame) {
  if (!pluginAvailable(frame.url)) return;
  if (isHelperCacheFresh()) return;
  sendAuthenticatedBackendRequest(
    '/suggest/helpers',
    'get',
    {},
    (data) => {
      saveSuggestHelpers(data.helpers);
    },
    (error) => {
    }
  );
}

function getContentScriptPlugin(frame) {
  if (((frame.url.includes('connect.aws') && frame.url.includes('ccp-v2')) || frame.url.includes('awsapps') || frame.url.includes('amazonaws.com') || frame.url.includes('deliveroo-connect')) &&
      !frame.url.includes('task-list') && !frame.url.includes('customer-profiles')) {
    return 'scripts/plugin_overrides_connect.js';
  }
  return '';
}

function injectRemotePlugins(tabId, frame) {
  if (!pluginAvailable(frame.url)) {
    return;
  }
  if (getContentScriptPlugin(frame)) {
    chrome.scripting
      .executeScript({
        target: { tabId, frameIds: [frame.frameId] },
        files: [getContentScriptPlugin(frame)],
      })
      .then(() => {});
    return;
  }
  if (frame.url in SUGGEST_PLUGIN && isPluginCacheFresh(frame.url)) {
    if (SUGGEST_PLUGIN[frame.url]) {
      chrome.tabs.sendMessage(
        tabId,
        {
          action: 'init/SUGGEST_PLUGIN',
          plugin: SUGGEST_PLUGIN[frame.url],
        },
        { frameId: frame.frameId },
      ).catch(e => void e);
    }
  } else {
    sendAuthenticatedBackendRequest(
      '/suggest_plugin_overrides',
      'post',
      { url: frame.url },
      (data) => {
        SUGGEST_PLUGIN[frame.url] = data.code;
        const currentDate = new Date();
        PLUGIN_SET_TIME_MILLISECONDS[frame.url] = currentDate.getTime();
        if (SUGGEST_PLUGIN[frame.url]) {
          chrome.tabs.sendMessage(
            tabId,
            {
              action: 'init/SUGGEST_PLUGIN',
              plugin: SUGGEST_PLUGIN[frame.url],
            },
            { frameId: frame.frameId },
          ).catch(e => void e);
        }
      },
      (data) => {
        console.log("remote plugin error:", data);
      },
    );
  }
}

function isHelperCacheFresh() {
  if (SAPLING_ENV.MODE === 'development') {
    return false;
  }
  const currentDate = new Date();
  const currentTime = currentDate.getTime();
  if ((currentTime - HELPERS_SET_TIME_MILLISECONDS) < TIME_DELTA) {
    return true;
  }
  return false;
}

function isPluginCacheFresh(url) {
  const currentDate = new Date();
  const currentTime = currentDate.getTime();
  if (url in PLUGIN_SET_TIME_MILLISECONDS && (currentTime - PLUGIN_SET_TIME_MILLISECONDS[url]) < TIME_DELTA) {
    return true;
  }
  return false;
}
