import * as Sentry from '@sentry/browser';

import { SAPLING_ENV } from './globals';
import './listeners';
import './listeners/requests';
import './users';
import { setCustomEndpointsPromise } from './requests/utils';
import startChromiumIssue1316588Watcher from './fix_mv3_service_worker';

const MAX_SCRATCHPAD_TIME_SAVED_MS = 4 * 60 * 60 * 1000;

const sendMessageToRequesterTab = (sender, message, options, responseCallback) => {
  const senderTabId = sender && sender.tab && sender.tab.id;
  const sendMessage = (tabId) => {
    if (typeof tabId !== 'number') {
      return;
    }

    if (responseCallback) {
      chrome.tabs.sendMessage(tabId, message, options, responseCallback);
      return;
    }

    if (options) {
      chrome.tabs.sendMessage(tabId, message, options).catch(e => void e);
    } else {
      chrome.tabs.sendMessage(tabId, message).catch(e => void e);
    }
  };

  if (typeof senderTabId === 'number') {
    sendMessage(senderTabId);
    return;
  }

  chrome.tabs.query({ active: true, currentWindow: true }, (tabs) => {
    if (tabs && tabs.length > 0) {
      sendMessage(tabs[0].id);
    }
  });
};

if (SAPLING_ENV.SENTRY_DSN) {
  const manifestData = chrome.runtime.getManifest();
  const IGNORE_ERRORS = [
    'The frame was removed',
    'No frame with id',
    'Attempting to use a disconnected port object',
    // Slack CustomEvent objects thrown as promise rejections (plain object form)
    'Non-Error promise rejection captured with keys: bubbles, cancelBubble, cancelable, composed, currentTarget, defaultPrevented, detail, eventPhase, isTrusted, returnValue, srcElement, target, timeStamp, type',
    // Other CustomEvent promise rejections from Slack with different property order
    'Non-Error promise rejection captured with keys: type, target, currentTarget, eventPhase, bubbles, cancelable, defaultPrevented, composed, timeStamp, srcElement, returnValue, cancelBubble, detail, isTrusted',
    // Slack CustomEvent instances thrown as unhandled rejections (Sentry formats these differently from plain objects)
    'Event `CustomEvent` (type=unhandledrejection) captured as promise rejection',
    // Microsoft Teams internal web worker noise — not Sapling code
    'AsyncIterableObserver buffer is full',
    // Microsoft Teams wraps unhandled rejections as synchronous errors with this prefix
    'UPR: ',
    // Chrome API errors when no browser window is focused (e.g. all windows minimised)
    'No current window',
    // Chrome API errors when the service worker is not yet registered on first load
    // Using regex to match exact error to avoid suppressing unrelated errors containing "No SW"
    /^No SW$/,
    // Chrome IndexedDB / LevelDB internal errors — not from Sapling code, not actionable
    'IO error:',
    'Corruption: not an sstable (bad magic number)',
  ];
  Sentry.init({
    dsn: SAPLING_ENV.SENTRY_DSN,
    sampleRate: 0.0001,
    release: manifestData.version,
    ignoreErrors: IGNORE_ERRORS,
    denyUrls: [
      // Microsoft Teams internal web worker scripts
      /teams-modular-packages/,
      // Microsoft Teams precompiled web worker scripts (source of UPR-prefixed errors)
      /\/v2\/worker\//,
    ],
    beforeSend(event, hint) {
      const error = hint.originalException;
      if (error && error.message) {
        if (IGNORE_ERRORS.some(pattern => {
          if (pattern instanceof RegExp) {
            return pattern.test(error.message);
          }
          return error.message.includes(pattern);
        })) {
          return null;
        }
      }
      // Fallback: check the processed exception value for errors where originalException
      // is null (e.g. web-worker errors propagated to window.onerror without an Error object)
      const eventExceptionValue = event.exception &&
        event.exception.values &&
        event.exception.values[0] &&
        event.exception.values[0].value;
      if (eventExceptionValue) {
        if (IGNORE_ERRORS.some(pattern => {
          if (pattern instanceof RegExp) {
            return pattern.test(eventExceptionValue);
          }
          return eventExceptionValue.includes(pattern);
        })) {
          return null;
        }
      }
      return event;
    },
  });
  Sentry.configureScope((scope) => {
    scope.setTag('version', manifestData.version);
    scope.setTag('background', true);
  });
}

try {
  setCustomEndpointsPromise();
  chrome.runtime.setUninstallURL(`${SAPLING_ENV.WEBSITE_URL}/uninstall`);

  chrome.runtime.onConnect.addListener((externalPort) => {
    externalPort.onMessage.addListener((msg) => {
      chrome.storage.local.set({
        popupStorage: {
          html: msg,
          updatedAt: Date.now(),
        },
      });
    });
  });

  startChromiumIssue1316588Watcher();

  chrome.commands.onCommand.addListener((command) => {
    if (command === 'accept-all-edits' ||
        command === 'accept-current-sentence-edits' ||
        command === 'toggle-snippet-controls' ||
        command === 'toggle-rephrase-controls'
    ) {
      // send keyboard shortcuts to active tab
      chrome.tabs.query({ active: true, lastFocusedWindow: true }, (tabs) => {
        if (tabs && tabs.length > 0) {
          chrome.tabs.sendMessage(tabs[0].id, { action: command }).catch(e => void e);
        }
      });
      // special case to propagate command to popup, which is not a tab
      chrome.runtime.sendMessage({ action: `${command}-popup` }).catch(e => void e);
    }
  });

  chrome.webNavigation.onHistoryStateUpdated.addListener((details) => {
    chrome.tabs.sendMessage(
      details.tabId,
      { action: 'init/HISTORY_PUSHSTATE' },
    ).catch(e => void e);
  });

  chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
    if (!request) {
      return false;
    }

    if (request.action === 'popup/GET_HTML') {
      chrome.storage.local.get('popupStorage', (obj) => {
        let popupHtml = '';
        const { popupStorage } = obj;
        if (typeof popupStorage !== 'undefined') {
          const { html, updatedAt } = popupStorage;
          if (updatedAt) {
            if ((Date.now() - updatedAt) <= MAX_SCRATCHPAD_TIME_SAVED_MS) {
              popupHtml = html;
            } else {
              chrome.storage.local.remove('popupStorage');
            }
          }
        }
        sendResponse({ status: true, success: true, data: { popupHtml } });
      });
      return true; // signal async response
    } else if (request.action === 'snippet-add') {
      // pass request back to the content scripts in the sender tab
      sendMessageToRequesterTab(sender, request);
    } else if (request.action === 'snippet-selected') {
      // pass request back to the content scripts in the sender tab
      sendMessageToRequesterTab(sender, request);
    } else if (request.action === 'hide-snippet-controls') {
      // pass request back to the content scripts in the sender tab
      sendMessageToRequesterTab(sender, request);
    } else if (request.action === 'snippet-focus-found') {
      // pass request back to the content scripts in the sender tab
      sendMessageToRequesterTab(sender, request);
    } else if (request.action === 'snippet-control') {
      // pass request back to the content scripts in the sender tab
      sendMessageToRequesterTab(sender, { action: 'snippet-control', data: request.data });
    } else if (request.action === 'get-session-id') {
      // get session ID from parent page/URL
      // then send that back to the requester
      sendMessageToRequesterTab(sender, request, { frameId: 0 }, sendResponse); // Just top frame
      return true; // signal async response
    } else if (request.action === 'get-iframe-bounding-rect') {
      // cross-origin workaround to get global iframe position from the iframe's content script
      // track the original tabId and frameId
      const senderTabId = sender && sender.tab && sender.tab.id;
      if (!request.tabId) {
        request.tabId = senderTabId;
      }
      if (typeof request.tabId !== 'number') {
        return false;
      }
      if (typeof request.frameId !== 'number') {
        request.frameId = sender.frameId;
      }
      // don't pass request back to sender frame
      if (request.frameIds.includes(sender.frameId)) {
        return false;
      }
      request.frameIds.push(sender.frameId);

      chrome.webNavigation.getAllFrames(
        {
          tabId: request.tabId,
        },
      ).then((frames) => {
        for (let i = 0; i < frames.length; i++) {
          // don't pass request back to previous sender frame
          if (request.frameIds.includes(frames[i].frameId)) {
            continue;
          }
          request.user_data = frames[i].frameId;
          // pass request back to other content scripts (frames) in the sender tab
          chrome.tabs.sendMessage(
            request.tabId,
            request,
            { frameId: frames[i].frameId },
          ).catch(e => void e);
        }
      });
    } else if (request.action === 'return-iframe-bounding-rect') {
      chrome.tabs.sendMessage(
        request.tabId,
        request,
        { frameId: request.frameId },
      ).catch(e => void e);
    }
    return false;
  });
} catch (e) {
  Sentry.captureEvent(e);
  throw e;
}

chrome.offscreen.createDocument({
  url: 'generated/clipboard.html',
  reasons: [chrome.offscreen.Reason.CLIPBOARD],
  justification: 'Clipboard operations for snippets.',
}).catch(e => {
  if (e.message && !e.message.includes('Only a single offscreen document may be created')) {
    Sentry.captureException(e);
  }
});
