import _ from 'lodash';

import { getUser } from '../requests';
import saplingExecCommandOverride from '../execOverride';
import figmaGlobals from '../figma';

import {
  syncSuggestPluginSettings,
  getSuggestHelpers,
} from '../requests/cache/get-suggest-plugin';

// TODO: move. state will not be gauranteed here

let SAPLING_INIT_TAB_IDS = {}; // map from tab_id to set();
let SAPLING_INIT_TAB_COUNTS = {}; // map from tab_id to {} to counts;
let SAPLING_INIT_TAB_TIMESTAMPS = {}; // map from tab_id to {} to timestamps where first tried to inject into frame;

chrome.tabs.onRemoved.addListener((tabId, removeInfo) => {
  delete SAPLING_INIT_TAB_IDS[tabId];
});

// Reset toolbar icon badge
chrome.action.setBadgeText({ text: '' });

chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
  if (!request) {
    return false;
  }

  if (request.action === 'makeToolbarIconActive') {
    chrome.action.setIcon({ path: '/generated/sapling-32x32.png' });
    chrome.action.setBadgeText({ text: '' });
    chrome.action.setTitle({ title: 'Sapling is ready to go.' });
    sendResponse({ status: true, success: true });
  } else if (request.action === 'makeToolbarIconInactive') {
    chrome.action.setIcon({ path: '/assets/sapling-inactive-32x32.png' });
    chrome.action.setBadgeText({ text: '' });
    chrome.action.setTitle({ title: 'Sapling disabled.' });
    sendResponse({ status: true, success: true });
  } else if (request.action === 'makeToolbarIconThrottled') {
    chrome.action.setIcon({ path: '/assets/sapling-inactive-32x32.png' });
    chrome.action.setBadgeText({ text: '!' });
    chrome.action.setBadgeBackgroundColor({ color: 'orange' });
    chrome.action.setTitle({ title: 'Daily limit exceeded for this site.' });
    sendResponse({ status: true, success: true });
  } else if (request.action === 'makeToolbarIconLoading') {
    chrome.action.setBadgeText({ text: '*' });
    chrome.action.setBadgeBackgroundColor({ color: '#3f51b5' });
    chrome.action.setTitle({ title: 'Loading edits...' });
    sendResponse({ status: true, success: true });
  } else if (request.action === 'updateToolbarIconEditCount') {
    const count = request.data.editCount;
    if (count === 0) {
      chrome.action.setBadgeText({ text: '0' });
      chrome.action.setBadgeBackgroundColor({ color: '#3f51b5' });
      chrome.action.setTitle({ title: 'No errors detected!' });
    } else {
      chrome.action.setBadgeText({ text: count.toString() });
      chrome.action.setBadgeBackgroundColor({ color: '#F00' });
      const message = `${count.toString()} ${(count === 1) ? 'error' : 'errors'} detected.`;
      chrome.action.setTitle({ title: message });
    }
    sendResponse({ status: true, success: true });
  } else if (request.action === 'updateToolbarIconDisconnected') {
    chrome.action.setBadgeText({ text: '-' });
    chrome.action.setBadgeBackgroundColor({ color: 'black' });
    chrome.action.setTitle({ title: 'Cannot connect to server.' });
    sendResponse({ status: true, success: true });
  } else if (request.action === 'init/CHECK_CONTENT_SCRIPT_ACTIVE') {
    sendResponse({ status: true, success: true });
  } else if (request.action === 'background/GRAMMAR_OR_COMPLETE_TOGGLED') {
    const params = {
      hostname: request.hostname,
      observersOn: request.observersOn,
      observersOff: request.observersOff,
      action: 'event/GRAMMAR_OR_COMPLETE_TOGGLED',
    };
    chrome.tabs.query({}, (tabs) => {
      for (let i = 0; i < tabs.length; i++) {
        chrome.tabs.sendMessage(
          tabs[i].id,
          params,
        ).catch(e => void e);
      }
    });
    sendResponse({ status: true, success: true });
  } else if (request.action === 'background/get_suggest_helpers') {
    let suggestHelpers = getSuggestHelpers(request.hostname);
    sendResponse({ status: true, success: true, data: suggestHelpers });
  } else if (request.action === 'background/chat_event_bubble') {
    if (request.resetTimer) {
      // Update timer in active tab
      chrome.tabs.query({ active: true, lastFocusedWindow: true }, (tabs) => {
        if (tabs && tabs.length > 0) {
          chrome.tabs.sendMessage(
            tabs[0].id,
            { resetTimer: true },
          ).catch(e => void e);
        }
      });
    } else if (request.hideTimer) {
      // Remove in active tab
      chrome.tabs.query({ active: true, lastFocusedWindow: true }, (tabs) => {
        if (tabs && tabs.length > 0) {
          chrome.tabs.sendMessage(
            tabs[0].id,
            { hideTimer: true },
          ).catch(e => void e);
        }
      });
    }
  }
  return false;
});

function isTabWithValidUrl(tab) {
  if (!tab) {
    return false;
  }
  let { url } = tab;
  if (EXTENSION_BROWSER === 'edge') {
    // TODO Determine whether chrome:// okay
    return !url.startsWith('chrome://') && !url.startsWith('ms-browser-extension://') &&
      !url.startsWith('chrome-error://') && !url.startsWith('about:');
  }
  if (EXTENSION_BROWSER === 'ff') {
    // FF uses chrome:// too, not sure about chrome-error://
    return !url.startsWith('chrome://') && !url.startsWith('moz-extension://') &&
      !url.startsWith('chrome-error://') && !url.startsWith('about:');
  }
  return !url.startsWith('chrome://') && !url.startsWith('chrome-extension://') &&
    !url.startsWith('chrome-error://');
}

const injectIfNotInitializedThrottled = _.wrap(_.memoize(() => _.throttle(
  (tabId) => injectIfNotInitialized(tabId),
  2000,
  {
    leading: true,
    trailing: true,
  },
)), (func, obj) => func(obj)(obj));

function injectIntoFrame(tabId, frame, fetchPlugins) {
  chrome.runtime.getManifest().content_scripts.forEach((contentScript) => {
    // only inject main content script
    if (!contentScript.matches.includes('https://sapling.ai/main_declarative_injection_dont_remove')) return;
    if (contentScript.css) {
      chrome.scripting.insertCSS({
        files: contentScript.css,
        target: {
          tabId,
          frameIds: [frame.frameId],
        },
      }).catch(e => void e);
    }
    injectContentScriptSerial(tabId, frame, 0, contentScript.js, fetchPlugins);
  });

  if (frame.url.includes('figma.com')) {
    chrome.scripting.executeScript(
      {
        func: figmaGlobals,
        target: {
          tabId,
          allFrames: true,
        },
        world: 'MAIN',
      },
    ).catch(e => void e);
  }

  chrome.scripting.executeScript(
    {
      func: saplingExecCommandOverride,
      target: {
        tabId,
        allFrames: true,
      },
      world: 'MAIN',
    },
  ).catch(e => void e);
}

chrome.webNavigation.onCommitted.addListener((details) => {
  if (details.frameType !== 'sub_frame') {
    SAPLING_INIT_TAB_IDS[details.tabId] = new Set();
    SAPLING_INIT_TAB_COUNTS[details.tabId] = {};
    SAPLING_INIT_TAB_TIMESTAMPS[details.tabId] = {};
  }
});

function injectIfNotInitialized(tabId) {
  chrome.webNavigation.getAllFrames({ tabId }, (frames) => {
    if (!frames) {
      return;
    }

    // Top frame
    let topFrame = frames[0];
    frames.forEach((frame) => {
      if (frame.frameId === 0) topFrame = frame;
    });

    // if user has suggest flag, fetch remote plugin overrides after regular scripts
    getUser((resp) => {
      const fetchPlugins = resp.data && resp.data.suggest;

      frames.forEach((frame) => {
        // Salesforce editor frames are 'about:blank' for some reason
        if ((topFrame.url.includes('EmailTemplate') || topFrame.url.includes('QuickText')) &&
             frame.url === 'about:blank') {
          return;
        }
        if (frame.errorOccurred) {
          return;
        }
        let initFrameIds = SAPLING_INIT_TAB_IDS[tabId];
        let initFrameCounts = SAPLING_INIT_TAB_COUNTS[tabId];
        let initFrameTimestamps = SAPLING_INIT_TAB_TIMESTAMPS[tabId];
        if (initFrameIds === undefined) {
          initFrameIds = new Set();
          initFrameCounts = {};
          initFrameTimestamps = {};
          SAPLING_INIT_TAB_IDS[tabId] = initFrameIds;
          SAPLING_INIT_TAB_COUNTS[tabId] = initFrameCounts;
          SAPLING_INIT_TAB_TIMESTAMPS[tabId] = initFrameTimestamps;
        }
        let frameKey = `${frame.frameId}:${frame.url}`;
        if (initFrameIds.has(frame.frameId)) {
          // we've injected into this frame id before
          if (initFrameCounts[frameKey] <= 5 ||
              (frame.url && !frame.url.includes('connect.aws') && !frame.url.includes('awsapps') && !frame.url.includes('amazonaws.com') &&
                !frame.url.includes('acorns') && !frame.url.includes('saplingai.zendesk')) ||
              (frame.url && frame.url.includes('30460.apps.zdusercontent.com')) ||
              Date.now() / 1000 - initFrameTimestamps[frameKey] < 10) {
            initFrameCounts[frameKey] += 1;
            chrome.tabs.sendMessage(
              tabId,
              { action: 'init/CONTENT_SCRIPT_LOADED' },
              { frameId: frame.frameId },
            ).catch(e => {
              void e;
              injectIntoFrame(tabId, frame, fetchPlugins);
            });
          }
        } else {
          initFrameIds.add(frame.frameId);
          initFrameCounts[frameKey] = 1;
          initFrameTimestamps[frameKey] = Date.now() / 1000;
          injectIntoFrame(tabId, frame, fetchPlugins);
        }
      }); // end frames.forEach
    }, false); // end getUser()
  });
}

function injectContentScriptSerial(tabId, frame, i, scripts, fetchPlugins) {
  // initialize jQuery + other dependancies before other scripts
  chrome.scripting.executeScript(
    {
      files: [scripts[i]],
      target: {
        tabId,
        frameIds: [frame.frameId],
      },
    },
    (results) => {
      if (chrome.runtime.lastError) {
        // (This page cannot be scripted due to an ExtensionsSettings policy)
        return;
      }
      if (i < (scripts.length - 1)) {
        injectContentScriptSerial(tabId, frame, i + 1, scripts, fetchPlugins);
      } else if (fetchPlugins) {
        // suggest plugins need other content scripts initialized first
        syncSuggestPluginSettings(tabId, frame);
      }
    },
  );
}

chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
  // all_frames in manifest not sufficient
  if (request.action === 'init/NEW_IFRAME_LOADED') {
    if (sender.tab) {
      injectIfNotInitializedThrottled(sender.tab.id);
    }
    sendResponse({ status: true, success: true });
  } else if (request.action === 'init/GET_LOCATION') {
    if (sender.tab) {
      chrome.webNavigation.getFrame({ tabId: sender.tab.id, frameId: 0 }, (frame) => {
        if (frame) {
          sendResponse({ status: true, success: true, data: { url: frame.url } });
        } else {
          sendResponse({ status: true, success: true, data: { url: '' } });
        }
      });
    } else {
      chrome.tabs.query({ lastFocusedWindow: true, active: true }, (tabs) => {
        if (tabs && tabs.length > 0) {
          sendResponse({ status: true, success: true, data: { url: tabs[0].url } });
        } else {
          sendResponse({ status: true, success: true, data: { url: '' } });
        }
      });
    }
    return true; // returning asynchronously
  }

  return false;
});

// The below code is responsible for making sure all active tabs
// have a valid content script.  Content scripts get invalidated
// on update/installs.  Inject content script if doesn't exist.
// WARNING: there is the possibility that two content scripts get
// loaded if tab.status != "complete".
chrome.tabs.onActivated.addListener((activeInfo) => {
  chrome.tabs.get(activeInfo.tabId, (tab) => {
    if (isTabWithValidUrl(tab) && tab.status === 'complete') {
      injectIfNotInitializedThrottled(tab.id);
    }
  });
});
chrome.tabs.onUpdated.addListener((tabId, changeInfo, tab) => {
  if (isTabWithValidUrl(tab) && tab.active && changeInfo.status === 'complete') {
    injectIfNotInitializedThrottled(tab.id);

    // some websites put iframes in closed shadow doms, no way to catch them in dom traversal
    // do some final sweeps after the page is loaded;
    setTimeout(() => injectIfNotInitializedThrottled(tab.id), 4000);
    setTimeout(() => injectIfNotInitializedThrottled(tab.id), 8000);
    setTimeout(() => injectIfNotInitializedThrottled(tab.id), 16000);
  }
});
chrome.tabs.query({ active: true }, (tabs) => {
  for (let i = 0; i < tabs.length; i += 1) {
    const tab = tabs[i];
    if (isTabWithValidUrl(tab) && tab.status === 'complete') {
      injectIfNotInitializedThrottled(tab.id);
    }
  }
});
