import * as Sentry from '@sentry/browser';

import {
  forgotPassword,
  getAIDetectionScores,
  getBanners,
  getCompletion,
  getEdits,
  getMatchSuggest,
  getPopupMessage,
  getRephrase,
  getSettings,
  getShortcutSnippets,
  getSnippets,
  getStatistics,
  getSuggest,
  getTone,
  getUser,
  getUserUsage,
  loginUser,
  logoutUser,
  postChatEvent,
  postChatTurn,
  postCompletion,
  postEdit,
  postRephrase,
  postSettings,
  postSuggestionEvent,
  postSuggestionSelect,
  postToneFeedback,
  qualityQuery,
  registerUser,
  resendEmailConfirmation,
  selectSnippet,
  sendEvent,
} from '../requests';
import { clearUserCache } from '../requests/cache/get-user';

chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
  try {
    const { data, action } = request;
    if (action === 'request/GET_EDITS') {
      getEdits(data.html, data.sessionId, data.context, sendResponse);
    } else if (action === 'request/GET_REPHRASE') {
      getRephrase(data.html, data.mapping, data.metadata, data.sessionId, data.context, sendResponse);
    } else if (action === 'request/GET_REPHRASE_SHORTCUT') {
      let scut = null;
      chrome.commands.getAll((commands) => {
        for (let { name, shortcut } of commands) {
          if (name === 'toggle-rephrase-controls') {
            scut = shortcut;
            break;
          }
        }
        sendResponse({ data: { shortcut: scut }, status: true, success: true });
      });
    } else if (action === 'request/GET_STATISTICS') {
      getStatistics(data.html, data.sessionId, data.context, sendResponse);
    } else if (action === 'request/GET_TONE') {
      getTone(data.html, data.sessionId, data.context, sendResponse);
    } else if (action === 'request/POST_TONE_FEEDBACK') {
      postToneFeedback(data.html, data.toneData, data.textType, data.score, data.sessionId, data.context, sendResponse);
    } else if (action === 'request/GET_COMPLETION') {
      getCompletion(data.query, data.sessionId, data.context, sendResponse);
    } else if (action === 'request/GET_SUGGEST') {
      getSuggest(data.query, data.multiquery, data.context, sendResponse);
    } else if (action === 'request/GET_MATCH_SUGGEST') {
      getMatchSuggest(data.inp, data.context, sendResponse);
    } else if (action === 'request/SEND_EVENT') {
      sendEvent(data.eventAction, data.context);
      sendResponse({ status: true, success: true });
    } else if (action === 'request/POST_EDIT') {
      postEdit(data.editHash, data.sessionId, data.action, data.context);
      sendResponse({ status: true, success: true });
    } else if (action === 'request/POST_REPHRASE') {
      postRephrase(data.rephraseHash, data.sessionId, data.action, data.context);
      sendResponse({ status: true, success: true });
    } else if (action === 'request/POST_COMPLETION') {
      postCompletion(data.completionHash, data.sessionId, data.action, data.context);
    } else if (action === 'request/POST_SUGGESTION_SELECT') {
      postSuggestionSelect(data.suggestionId, data.context);
      sendResponse({ status: true, success: true });
    } else if (action === 'request/POST_SUGGESTION_EVENT') {
      postSuggestionEvent(data);
      sendResponse({ status: true, success: true });
    } else if (action === 'request/POST_CHAT_EVENT') {
      postChatEvent(data.context);
      sendResponse({ status: true, success: true });
    } else if (action === 'request/POST_CHAT_TURN') {
      postChatTurn(data.context);
      sendResponse({ status: true, success: true });
    } else if (action === 'request/POST_SETTINGS') {
      postSettings(data.settings, data.context);
      sendResponse({ status: true, success: true });
    } else if (action === 'request/GET_SETTINGS') {
      getSettings(data.hostname, data.pathname, data.context, sendResponse);
    } else if (action === 'request/GET_BANNERS') {
      getBanners(data.hostname, data.pathname, data.context, sendResponse);
    } else if (action === 'request/GET_USER') {
      getUser(sendResponse, data.ignoreCache);
    } else if (action === 'request/CLEAR_USER') {
      clearUserCache();
      sendResponse({ status: true, success: true });
    } else if (action === 'request/GET_USER_USAGE') {
      getUserUsage(sendResponse);
    } else if (action === 'request/GET_POPUP_MESSAGE') {
      getPopupMessage(sendResponse);
    } else if (action === 'request/REGISTER_USER') {
      registerUser(data.email, data.password, sendResponse);
    } else if (action === 'request/LOGIN_USER') {
      loginUser(data.email, data.password, sendResponse);
    } else if (action === 'request/LOGOUT_USER') {
      logoutUser(sendResponse);
    } else if (action === 'request/RESEND_EMAIL_CONFIRMATION') {
      resendEmailConfirmation(sendResponse);
    } else if (action === 'request/FORGOT_PASSWORD') {
      forgotPassword(data.email, sendResponse);
    } else if (action === 'request/GET_SNIPPETS') {
      getSnippets(data.queryTerms, data.context, sendResponse);
    } else if (action === 'request/SELECT_SNIPPET') {
      selectSnippet(data.snippetId, data.mode, data.queryTerms, data.queryCount, data.context);
    } else if (action === 'request/GET_SHORTCUT_SNIPPETS') {
      getShortcutSnippets(sendResponse);
    } else if (action === 'request/GET_AI_DETECTION_SCORES') {
      getAIDetectionScores(data.html, data.sessionId, data.context, sendResponse);
    }
  } catch (e) {
    Sentry.captureException(e);
    sendResponse({ status: true, success: false, data: { message: 'Error in background script.' } });
  }

  return true;
});

chrome.runtime.onMessageExternal.addListener((request, sender, sendResponse) => {
  if (request.data && request.data.content_html)
    qualityQuery(request);
});
